const typeInput = $('Webhook').first().json.body.Type;

function getScheduleType(input) {
  if (input === "assignment") {
    return "weekly";
  }

  const semTypes = ["documentary", "shortfilm", "feature film", "episodic content"];
  if (semTypes.includes(input)) {
    return "sem";
  }

  return "unknown";
}

const result = getScheduleType(typeInput);

return [
  {
    schedule: result
  }
];
